previewCss:
.darma-loader-uiverse-golden-star-badge {
  --dim: 5rem;
  background-color: var(--loader-color, #ed8a19);
  width: var(--dim);
  height: var(--dim);
  border-radius: 50%;
  display: grid;
  place-items: center;
  animation: darma-loader-uiverse-golden-star-badge-spin_412 5s infinite;
}

.darma-loader-uiverse-golden-star-badge .darma-loader-uiverse-golden-star-badge__svg {
width: 68%;
height: 68%;
transform: translateY(-2px);
}

@keyframes darma-loader-uiverse-golden-star-badge-spin_412 {
0% {
transform: rotate(0) scale(1);
}

50% {
transform: rotate(720deg) scale(1.18);
}

100% {
transform: rotate(0) scale(1);
}
}

